let raw = $input.item.json.choices?.[0]?.message?.content || "{}";
let payload = {};

const match = raw.match(/\{[\s\S]*\}/);
if (match) raw = match[0];

try {
  payload = JSON.parse(raw);

  if (!payload.titulo) payload.titulo = "Captura de Idea";
  if (!payload.descripcion) payload.descripcion = $('Execute Workflow Trigger').item.json.texto_usuario;
  if (!payload.categoria) payload.categoria = "General";
  if (!payload.accion_sugerida) payload.accion_sugerida = "Revisar manualmente";
  if (!payload.prioridad) payload.prioridad = "media";
  if (!payload.tipo_tarea) payload.tipo_tarea = "operativa";

} catch(e) {
  payload = {
    titulo: "Fallo Extracción JSON",
    descripcion: $('Execute Workflow Trigger').item.json.texto_usuario,
    categoria: "Error",
    accion_sugerida: "Forzado por Fallback",
    prioridad: "media",
    tipo_tarea: "operativa"
  };
}
return { json: { payload: payload } };

